arguments.argument:
if global.gamePaused=false
{
  x+=moveSpd
  
  if room=rWarshipZ_E3 //EX MODE
  {
    if moveSpd>1 {moveSpd-=0.13}
    else if moveSpd<-1 {moveSpd+=0.13}
  }
  else
  {
    if moveSpd>1 {moveSpd-=0.15}
    else if moveSpd<-1 {moveSpd+=0.15}
  }
  
  image_alpha-=fadeSpd
  if image_alpha<=0.5 {instance_destroy()}
}
